code_changes.content:
[
  {
    "file": "source/common/http/header_utility.cc",
    "line": 43,
    "severity": "critical",
    "description": "Logic inversion in HeaderUtility::matchHeaders(). When a configured header matches the request headers, the function returns false, causing fault injection to be skipped. The logic is backwards: it should return true when headers match (allowing fault injection) and false when no headers match (blocking injection). This causes the fault filter to NOT inject faults on matching requests and TO inject faults on non-matching requests - the opposite of intended behavior.",
    "fix_patch": "--- a/source/common/http/header_utility.cc
+++ b/source/common/http/header_utility.cc
@@ -40,12 +40,12 @@ bool HeaderUtility::matchHeaders(const HeaderMap& request_headers,
   // No headers to match is considered a match.
   if (!config_headers.empty()) {
     for (const HeaderDataPtr& cfg_header_data : config_headers) {
       if (cfg_header_data->matchesHeaders(request_headers)) {
-        return false;
+        return true;
       }
     }
   }

-  return true;
+  return false;
 }
"
  },
  {
    "file": "source/extensions/filters/http/ext_authz/ext_authz.cc",
    "line": 502,
    "severity": "high",
    "description": "Missing route cache invalidation in ext_authz filter. When the external authorization check modifies request headers (via headers_to_set, headers_to_add, headers_to_append, headers_to_remove, or query parameter modifications), these changes can affect how the request is routed. The filter has a config option 'clear_route_cache_' and a getter method 'clearRouteCache()' but never calls 'decoder_callbacks_->clearRouteCache()' to invalidate the cached route. This causes downstream filters to use a stale route that was computed before header modifications, potentially routing requests to the wrong upstream cluster.",
    "fix_patch": "--- a/source/extensions/filters/http/ext_authz/ext_authz.cc
+++ b/source/extensions/filters/http/ext_authz/ext_authz.cc
@@ -722,6 +722,9 @@ void Filter::onComplete(Filters::Common::ExtAuthz::ResponsePtr&& response) {
       request_headers_->setPath(new_path);
     }

+    if (config_->clearRouteCache()) {
+      decoder_callbacks_->clearRouteCache();
+    }
     if (cluster_) {
       config_->incCounter(cluster_->statsScope(), config_->ext_authz_ok_);
     }
"
  },
  {
    "file": "source/extensions/filters/http/fault/fault_filter.cc",
    "line": 462,
    "severity": "medium",
    "description": "Incorrect gauge decrement condition in postDelayInjection(). When a delay completes without a following abort, the code decrements the active_faults_ gauge if 'isResponseRateLimitConfigured()' is true. However, the check should be whether the response rate limiter is actually ACTIVE (response_limiter_ != nullptr), not whether it's merely configured. If the response_limiter is active, the gauge should remain incremented to account for the ongoing fault impact. Using the config check instead of the actual state check can cause gauge accounting errors when response rate limiting is configured but not actually activated for a particular request.",
    "fix_patch": "--- a/source/extensions/filters/http/fault/fault_filter.cc
+++ b/source/extensions/filters/http/fault/fault_filter.cc
@@ -460,7 +460,7 @@ void FaultFilter::postDelayInjection(const Http::RequestHeaderMap& request_head
     ASSERT(fault_active_);
     ASSERT(delay_timer_ == nullptr);
-    if (isResponseRateLimitConfigured()) {
+    if (response_limiter_ == nullptr) {
       config_->stats().active_faults_.dec();
       fault_active_ = false;
     }
"
  },
  {
    "file": "source/common/http/filter_manager.cc",
    "line": 1294,
    "severity": "critical",
    "description": "Logic inversion in required response headers check. The condition 'if (status.ok())' sends a BadGateway error and stops processing, but this should only happen when the check FAILS (when status is NOT ok). The inverted logic means responses with valid required headers are rejected with BadGateway errors, while responses missing critical headers are allowed through. This breaks upstream response validation and allows malformed responses to be sent to clients.",
    "fix_patch": "--- a/source/common/http/filter_manager.cc
+++ b/source/common/http/filter_manager.cc
@@ -1291,7 +1291,7 @@ void FilterManager::encodeHeaders(ResponseHeaderMap& headers, bool end_stream,
   // filter chains.
   const auto status = HeaderUtility::checkRequiredResponseHeaders(headers);
-  if (status.ok()) {
+  if (!status.ok()) {
     // If the check failed, then we reply with BadGateway, and stop the further processing.
     sendLocalReply(
         Http::Code::BadGateway, status.message(), nullptr, absl::nullopt,
"
  }
]

